import type { ObjectId } from "mongodb";

export interface Digest {
  _id: ObjectId;
  content: string;
  createdAt: Date;
  misconception: string;
  scheduledFor: Date | null;
  sentAt: Date | null;
  series?: {
    name: string;
    part: number;
  };
  status: "draft" | "scheduled" | "sent";
  title: string;
  updatedAt: Date;
}

export interface Subscriber {
  _id: string;
  createdAt: Date | null;
  email: string;
  emailVerified: Date | null;
  image: string | null;
  name: string | null;
  role: string;
  token: string | null;
  tokenExpiresAt: Date | null;
}

export type SubscriberInsert = Omit<
  Subscriber,
  "role" | "createdAt" | "emailVerified" | "image" | "name"
> & {
  role?: string;
  createdAt?: Date | null;
  emailVerified?: Date | null;
  image?: string | null;
  name?: string | null;
};

import {
  Body,
  Button,
  Container,
  Head,
  Heading,
  Hr,
  Html,
  Img,
  Preview,
  Section,
  Text,
} from "@react-email/components";

interface DigestEmailProps {
  archiveUrl?: string;
  content: string;
  misconception: string;
  series?: {
    name: string;
    part: number;
  };
  title: string;
}

const baseUrl = process.env.NEXT_PUBLIC_APEX_URL ?? "https://hastoggle.dev";

export function DigestEmail({
  title,
  misconception,
  content,
  series,
  archiveUrl,
}: DigestEmailProps) {
  return (
    <Html>
      <Head />
      <Preview>{title}</Preview>
      <Body style={main}>
        <Container style={container}>
          <Img
            alt="hasToggle"
            height={42}
            src={`${baseUrl}/icon.png`}
            width={42}
          />
          {series && (
            <Text style={seriesLabel}>
              {series.name} &mdash; Part {series.part}
            </Text>
          )}
          <Heading style={heading}>{title}</Heading>
          <Text style={misconceptionStyle}>
            Misconception: &ldquo;{misconception}&rdquo;
          </Text>
          <Hr style={hr} />
          <Text style={body}>{content}</Text>
          {archiveUrl && (
            <Section style={ctaSection}>
              <Button href={archiveUrl} style={button}>
                Read in the app
              </Button>
            </Section>
          )}
          <Hr style={hr} />
          <Text style={footer}>
            You&apos;re receiving this because you subscribed to the hasToggle
            weekly digest.
          </Text>
        </Container>
      </Body>
    </Html>
  );
}

